### 1. **Python with Three.js (Web-Based 3D)**
You can use JavaScript with Three.js to render a 3D house in a web browser. Here's a basic example:

```javascript
import * as THREE from 'three';

// Scene setup
const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
const renderer = new THREE.WebGLRenderer();
renderer.setSize(window.innerWidth, window.innerHeight);
document.body.appendChild(renderer.domElement);

// Create house geometry
const houseGroup = new THREE.Group();

// Walls
const wallGeometry = new THREE.BoxGeometry(10, 6, 1);
const wallMaterial = new THREE.MeshLambertMaterial({ color: 0x8B4513 });
const wall = new THREE.Mesh(wallGeometry, wallMaterial);
houseGroup.add(wall);

// Roof
const roofGeometry = new THREE.ConeGeometry(8, 4, 4);
const roofMaterial = new THREE.MeshLambertMaterial({ color: 0x8B0000 });
const roof = new THREE.Mesh(roofGeometry, roofMaterial);
roof.position.y = 6;
houseGroup.add(roof);

// Add to scene
scene.add(houseGroup);
camera.position.z = 20;

// Render loop
function animate() {
    requestAnimationFrame(animate);
    renderer.render(scene, camera);
}
animate();
```

